        d_Col[d_unique_ptr[bx].point_no] = d_tColLoc[loc_pointer];

        d_in = d_T;

        int ei_new = tx;
        while (ei_new < d_common_ptr->in_elem) {

            row = ((ei_new + 1) % d_common_ptr->in_rows) - 1;
            col = ((ei_new + 1) / d_common_ptr->in_rows) + 1 - 1;
            if (((ei_new + 1) % d_common_ptr->in_rows) == 0) {
                row = d_common_ptr->in_rows - 1;
                col -= 1;
            }

            ori_row = d_Row[d_unique_ptr[bx].point_no] - 25 + row - 1;
            ori_col = d_Col[d_unique_ptr[bx].point_no] - 25 + col - 1;
            ori_pointer = ori_col * d_common_ptr->frame_rows + ori_row;

            d_in[ei_new] = d_common_ptr->alpha * d_in[ei_new] + (1.0f - d_common_ptr->alpha) * d_common_change_ptr->d_frame[ori_pointer];

            ei_new += NUMBER_THREADS;
        }
    }
}
